const now = new Date().toISOString();

const input = $input.first()?.json || {};
const context = input.context || {};

const client = context.client || {};
const trajet = context.trajet || {};
const devis = context.devis || {};
const pdf = context.pdf || {};

function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

const commercialEmail =
  input.commercial_email ||
  context.commercial?.email ||
  "jimmyribeiro69@gmail.com";

const nomClient = [client.prenom, client.nom].filter(Boolean).join(" ") || client.nom || "Client";
const subject = `Validation commerciale requise - Devis NeoTravel - ${nomClient}`;

const html = `
<p>Bonjour,</p>

<p>Un devis NeoTravel a été généré et nécessite une validation commerciale.</p>

<h3>Synthèse</h3>
<ul>
  <li><strong>Client :</strong> ${escapeHtml(nomClient)}</li>
  <li><strong>Email :</strong> ${escapeHtml(client.email || "Non renseigné")}</li>
  <li><strong>Trajet :</strong> ${escapeHtml(trajet.depart || "")} → ${escapeHtml(trajet.destination || "")}</li>
  <li><strong>Date :</strong> ${escapeHtml(trajet.date_depart || "Non renseignée")}</li>
  <li><strong>Passagers :</strong> ${escapeHtml(trajet.nb_passagers || "Non renseigné")}</li>
  <li><strong>Total TTC :</strong> ${escapeHtml(devis.total_ttc || "Non renseigné")} €</li>
</ul>

${
  pdf.drive_view_url
    ? `<p><a href="${escapeHtml(pdf.drive_view_url)}">Consulter le devis PDF</a></p>`
    : `<p>Aucun lien PDF trouvé.</p>`
}

<p>Action attendue : vérifier puis valider ou demander une modification.</p>
`;

return [
  {
    json: {
      success: true,
      message: "Email de validation commerciale préparé.",
      context,
      email: {
        type: "COMMERCIAL_VALIDATION",
        to: commercialEmail,
        subject,
        html
      },
      result: {
        entity: "email",
        type: "COMMERCIAL_VALIDATION"
      }
    }
  }
];

const now = new Date().toISOString();

const input = $input.first()?.json || {};
const context = input.context || {};

const client = context.client || {};
const trajet = context.trajet || {};
const errors = input.errors || context.errors || [];

function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

const commercialEmail =
  input.commercial_email ||
  context.commercial?.email ||
  "jimmyribeiro69@gmail.com";

const nomClient = [client.prenom, client.nom].filter(Boolean).join(" ") || client.nom || "Client";
const reason = input.reason || context.complexity?.reason || "Escalade commerciale demandée.";
const subject = `Escalade commerciale - Demande NeoTravel - ${nomClient}`;

const errorsHtml = errors.length
  ? errors.map(e => `<li>${escapeHtml(e.message || e.code || JSON.stringify(e))}</li>`).join("")
  : "<li>Aucune erreur technique transmise.</li>";

const html = `
<p>Bonjour,</p>

<p>Une demande NeoTravel nécessite une reprise commerciale humaine.</p>

<h3>Synthèse</h3>
<ul>
  <li><strong>Client :</strong> ${escapeHtml(nomClient)}</li>
  <li><strong>Email :</strong> ${escapeHtml(client.email || "Non renseigné")}</li>
  <li><strong>Trajet :</strong> ${escapeHtml(trajet.depart || "")} → ${escapeHtml(trajet.destination || "")}</li>
  <li><strong>Date :</strong> ${escapeHtml(trajet.date_depart || "Non renseignée")}</li>
  <li><strong>Passagers :</strong> ${escapeHtml(trajet.nb_passagers || "Non renseigné")}</li>
</ul>

<h3>Motif</h3>
<p>${escapeHtml(reason)}</p>

<h3>Éléments transmis</h3>
<ul>${errorsHtml}</ul>

<p>Action attendue : reprendre le dossier et décider de la suite commerciale.</p>
`;

return [
  {
    json: {
      success: true,
      message: "Email d'escalade commerciale préparé.",
      context,
      email: {
        type: "COMMERCIAL_ESCALATION",
        to: commercialEmail,
        subject,
        html
      },
      result: {
        entity: "email",
        type: "COMMERCIAL_ESCALATION"
      }
    }
  }
];

