const email = input.email || {};

context.email = {
  ...(context.email || {}),
  type: "COMMERCIAL_VALIDATION",
  recipient: email.to || null,
  subject: email.subject || null,
  sent: true,
  sent_at: now,
  status: "SENT"
};

context.last_tool = "WF_010_Send_Email";
context.last_update_at = now;

return [
{
json:{

success:true,

status:"EMAIL_SENT",

tool:"WF_010_Send_Email",

version:"3.0",

timestamp:now,

context,

message:"La demande de validation commerciale a été envoyée.",

next_action:"finish",

next_workflow:"",

next_payload:{},

error:null

}
}
];

