const now = new Date().toISOString();

const input = $("Generate_HTML_Client_Quote").first().json || {};

const context = JSON.parse(JSON.stringify(input.context || {}));

const email = input.email || {};

let airtableResult = {};

try {

  airtableResult = $("Update_Devis_Status").first().json || {};

} catch {

  airtableResult = {};

}

const airtableUpdated = !!airtableResult.id;

context.email = {
  ...(context.email || {}),
  type: "CLIENT_QUOTE",
  recipient: email.to || null,
  subject: email.subject || null,
  sent: true,
  sent_at: now,
  status: "SENT"
};

context.devis = {
  ...(context.devis || {}),
  status: airtableUpdated
    ? "en attente retour client"
    : context.devis?.status,
  email_sent_at: now
};

context.last_tool = "WF_010_Send_Email";
context.last_update_at = now;

return [
{
json:{

success:true,

status:"EMAIL_SENT",

tool:"WF_010_Send_Email",

version:"3.0",

timestamp:now,

context,

message: airtableUpdated
  ? "Le devis a été envoyé au client."
  : "Le devis a été envoyé au client mais le statut Airtable n'a pas pu être confirmé.",

next_action:"finish",

next_workflow:"",

next_payload:{},

error:null

}
}
];

const now = new Date().toISOString();

const input = $("Generate_HTML_Client_Quote").first().json || {};
const context = JSON.parse(JSON.stringify(input.context || {}));
const email = input.email || {};

let airtableResult = {};

try {
  airtableResult = $("Update_Devis_Status").first().json || {};
} catch (e) {
  airtableResult = {};
}

const airtableUpdated = !!airtableResult.id;

context.email = {
  ...(context.email || {}),
  type: "CLIENT_QUOTE",
  recipient: email.to || null,
  subject: email.subject || null,
  sent: true,
  sent_at: now,
  status: "SENT"
};

context.devis = {
  ...(context.devis || {}),
  status: airtableUpdated ? "en attente retour client" : context.devis?.status,
  email_sent_at: now
};

context.last_update_at = now;

return [
  {
    json: {
      success: true,
      message: airtableUpdated
        ? "Le devis a été envoyé au client et le statut Airtable a été mis à jour."
        : "Le devis a été envoyé au client, mais la mise à jour Airtable n'a pas été confirmée.",
      context,
      result: {
        entity: "email",
        type: "CLIENT_QUOTE",
        recipient: email.to || null,
        airtable_updated: airtableUpdated
      }
    }
  }
];

const now = new Date().toISOString();

const input = $input.first()?.json || {};
const context = input.context || {};

const client = context.client || {};
const trajet = context.trajet || {};
const devis = context.devis || {};
const pdf = context.pdf || {};

function isEmpty(value) {
  return value === undefined || value === null || value === "" || String(value).trim() === "";
}

function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

const errors = [];

if (isEmpty(client.email)) errors.push("context.client.email manquant");
if (isEmpty(devis.airtable_record_id)) errors.push("context.devis.airtable_record_id manquant");
if (isEmpty(pdf.drive_view_url)) errors.push("context.pdf.drive_view_url manquant");

if (errors.length > 0) {
  return [
    {
      json: {
        success: false,
        message: "Impossible de préparer l'email client : données manquantes.",
        context,
        result: {
          entity: "email",
          errors
        }
      }
    }
  ];
}

const nomClient = [client.prenom, client.nom].filter(Boolean).join(" ") || client.nom || "Client";
const subject = `Votre devis NeoTravel - ${trajet.depart || "Départ"} → ${trajet.destination || "Destination"}`;

const html = `
<p>Bonjour ${escapeHtml(nomClient)},</p>

<p>Suite à votre demande, vous trouverez ci-dessous la synthèse de votre devis NeoTravel.</p>

<h3>Synthèse de votre trajet</h3>
<ul>
  <li><strong>Trajet :</strong> ${escapeHtml(trajet.depart || "")} → ${escapeHtml(trajet.destination || "")}</li>
  <li><strong>Date de départ :</strong> ${escapeHtml(trajet.date_depart || "Non renseignée")}</li>
  <li><strong>Nombre de passagers :</strong> ${escapeHtml(trajet.nb_passagers || "Non renseigné")}</li>
  <li><strong>Montant TTC :</strong> ${escapeHtml(devis.total_ttc || "Non renseigné")} €</li>
</ul>

<p>
  <a href="${escapeHtml(pdf.drive_view_url)}">Consulter mon devis</a>
</p>

<p>Pour toute question ou modification, vous pouvez répondre directement à cet email.</p>

<p>Cordialement,<br>L’équipe NeoTravel</p>
`;

return [
  {
    json: {
      success: true,
      message: "Email client préparé.",
      context,
      email: {
        type: "CLIENT_QUOTE",
        to: client.email,
        subject,
        html
      },
      result: {
        entity: "email",
        type: "CLIENT_QUOTE"
      }
    }
  }
];

